import{k as i,b as a,c as l,G as t}from"./chunks/framework.Cb4zPKl6.js";const c=JSON.parse('{"title":"为 Avalonia 启用平滑滚动与缩放","description":"","frontmatter":{"date":"2026-04-09T00:00:00.000Z","title":"为 Avalonia 启用平滑滚动与缩放","slug":"enable-smooth-scroll-for-avalonia","tag":["C#","XAML","Avalonia"]},"headers":[],"relativePath":"posts/为 Avalonia 启用平滑滚动与缩放/index.md","filePath":"posts/为 Avalonia 启用平滑滚动与缩放/index.md"}'),n={name:"posts/为 Avalonia 启用平滑滚动与缩放/index.md"};function e(o,s,p,h,r,d){return a(),l("div",null,[...s[0]||(s[0]=[t(`<p>在 Avalonia 中，<code>ScrollViewer</code> 在鼠标滚轮下是没有平滑滚动的，看起来非常生硬。同时， <code>ScrollViewer</code> 也不支持平移、缩放等操作，这使得社区不得不使用为 <a href="https://github.com/wieslawsoltes/PanAndZoom" target="_blank" rel="noreferrer">PanAndZoom</a> 等第三方控件</p><p>为此，我编写了 <a href="https://github.com/zxbmmmmmmmmm/SmoothScroll.Avalonia" target="_blank" rel="noreferrer">SmoothScroll.Avalonia</a> 库，可以为应用中的所有 <code>ScrollViewer</code> 一键启用平滑滚动支持。同时，库中提供的 <code>ScrollView</code> 控件（继承自 <code>ScrollViewer</code>）还增加了平移和缩放功能</p><hr><div class="info custom-block"><p class="custom-block-title">这是一个<strong>实验性</strong>项目</p><p>当前实现需要使用 Avalonia 渲染层的一些内部 API</p></div><p>效果如下：</p><video id="video" controls=""><source id="mp4" src="/posts/%E4%B8%BA%20Avalonia%20%E5%90%AF%E7%94%A8%E5%B9%B3%E6%BB%91%E6%BB%9A%E5%8A%A8%E4%B8%8E%E7%BC%A9%E6%94%BE/1.mp4" type="video/mp4"></video><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><h3 id="启用-scrollviewer-的平滑滚动" tabindex="-1">启用 ScrollViewer 的平滑滚动 <a class="header-anchor" href="#启用-scrollviewer-的平滑滚动" aria-label="Permalink to “启用 ScrollViewer 的平滑滚动”">​</a></h3><p>安装 NuGet 包后，只需将 <code>ScrollViewerSmoothTheme</code> 添加到 <code>Application.Styles</code> 中即可</p><div class="language-xaml"><button title="Copy Code" class="copy"></button><span class="lang">xaml</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;Application</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    xmlns:smoothScroll</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;using:SmoothScroll.Avalonia.Controls&quot;</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;Application.Styles&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;...</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;smoothScroll:ScrollViewerSmoothTheme</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;/Application.Styles&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;/Application&gt;</span></span></code></pre></div><p>如果需要自定义样式，在你自己编写的 <code>ScrollViewer</code> 样式中将 <code>ScrollContentPresenter</code> 替换为包内提供的 <code>ScrollPresenter</code> 也可实现相同效果</p><h3 id="使用-scrollview-进行平移与缩放" tabindex="-1">使用 ScrollView 进行平移与缩放 <a class="header-anchor" href="#使用-scrollview-进行平移与缩放" aria-label="Permalink to “使用 ScrollView 进行平移与缩放”">​</a></h3><p><code>ScrollView</code> 是一个独立的控件。使用前，需要添加默认样式：</p><div class="language-xaml"><button title="Copy Code" class="copy"></button><span class="lang">xaml</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;Application</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    xmlns:smoothScroll</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;using:SmoothScroll.Avalonia.Controls&quot;</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;Application.Styles&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;...</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;smoothScroll:ScrollViewDefaultTheme</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;/Application.Styles&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;/Application&gt;</span></span></code></pre></div><p>它继承自 <code>ScrollViewer</code>，因此你可以将应用中的 <code>ScrollViewer</code> 直接替换为 <code>ScrollView</code> 来单独启用某处的平滑滚动。但与 <code>ScrollViewer</code> 不同的是，此控件还额外提供了缩放相关的属性和方法：</p><table tabindex="0"><thead><tr><th>属性/方法</th><th>描述</th></tr></thead><tbody><tr><td>bool IsZoomEnabled</td><td>是否启用缩放</td></tr><tr><td>double ZoomFactor</td><td>当前缩放倍率 (只读)</td></tr><tr><td>double MinZoomFactor</td><td>最小缩放倍率</td></tr><tr><td>double MaxZoomFactor</td><td>最小缩放倍率</td></tr><tr><td>void ZoomTo(double)</td><td>缩放到指定倍率</td></tr><tr><td>void ZoomBy(double)</td><td>按指定增量进行缩放</td></tr></tbody></table><p>例如，你可以将 <code>Image</code> 放入 <code>ScrollView</code> 中来创建一个图片查看器</p><div class="language-xaml"><button title="Copy Code" class="copy"></button><span class="lang">xaml</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;smoothScroll:ScrollView</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    HorizontalContentAlignment</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;Center&quot;</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    VerticalContentAlignment</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;Center&quot;</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    IsZoomEnabled</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;True&quot;</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    HorizontalScrollBarVisibility</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;Hidden&quot;</span></span>
<span class="line"><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;">    VerticalScrollBarVisibility</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;Hidden&quot;</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;Image</span><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;"> Source</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;avares://SmoothScroll.Avalonia.Sample//4074.bmp&quot;</span><span style="--shiki-light:#FF0000;--shiki-dark:#9CDCFE;"> Stretch</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">=</span><span style="--shiki-light:#A31515;--shiki-dark:#D69D85;">&quot;UniformToFill&quot;</span><span style="--shiki-light:#800000;--shiki-dark:#569CD6;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;/smoothScroll:ScrollView&gt;</span></span></code></pre></div><p><img src="/posts/%E4%B8%BA%20Avalonia%20%E5%90%AF%E7%94%A8%E5%B9%B3%E6%BB%91%E6%BB%9A%E5%8A%A8%E4%B8%8E%E7%BC%A9%E6%94%BE/1.png" alt=""></p><p>实现细节将会在下篇文章中进一步介绍！</p>`,20)])])}const g=i(n,[["render",e]]);export{c as __pageData,g as default};
